const n=(e,r="USD")=>{if(e==null||e==="")return"-";const t=Number(e);return Number.isNaN(t)?e:new Intl.NumberFormat("en-US",{style:"currency",currency:r,maximumFractionDigits:2}).format(t)},i=e=>{if(!e)return"-";const r=new Date(e);return Number.isNaN(r.getTime())?e:new Intl.DateTimeFormat("en-US",{month:"short",day:"numeric",year:"numeric"}).format(r)},a=e=>{if(!e)return"-";const r=new Date(e);return Number.isNaN(r.getTime())?e:new Intl.DateTimeFormat("en-US",{month:"short",day:"numeric",year:"numeric",hour:"numeric",minute:"2-digit"}).format(r)},o=e=>{if(!e)return"secondary";const r=String(e).toLowerCase();return["paid","active","completed","processed","succeeded"].includes(r)?"success":["pending","unpaid","processing"].includes(r)?"warning":["failed","cancelled","canceled","error"].includes(r)?"error":"info"},s=e=>e?String(e).replace(/_/g," ").replace(/\b\w/g,r=>r.toUpperCase()):"-";export{a,i as b,n as f,s as p,o as s};
